// Operator edit of a device's identity + management attributes (Edit Device).
// classification_locked, when set, also protects identity (category/vendor/model/
// serial) from being overwritten by future discovery scans (see the reconcile
// path UpdateDiscoveredDeviceRespectingLock).
func (q *Queries) UpdateDevice(ctx context.Context, arg UpdateDeviceParams) (Device, error) {
	row := q.db.QueryRow(ctx, updateDevice,
		arg.ID,
		arg.Name,
		arg.Category,
		arg.Vendor,
		arg.Model,
		arg.Serial,
		arg.OsVersion,
		arg.Hostname,
		arg.Vlan,
		arg.DeviceClass,
		arg.Location,
		arg.LocationID,
		arg.Subtype,
		arg.Notes,
		arg.Criticality,
		arg.MonitoringEnabled,
		arg.ClassificationLocked,
		arg.ManualClassificationReason,
	)
	var i Device
	err := row.Scan(
		&i.ID,
		&i.LocationID,
		&i.PrimaryIp,
		&i.Hostname,
		&i.Name,
		&i.Vendor,
		&i.Model,
		&i.Serial,
		&i.OsVersion,
		&i.Category,
		&i.Status,
		&i.Driver,
		&i.CredentialID,
		&i.LastDiscoveryAt,
		&i.LastMonitoringAt,
		&i.Metadata,
		&i.CreatedAt,
		&i.UpdatedAt,
		&i.DeletedAt,
		&i.Vlan,
		&i.DeviceClass,
		&i.Location,
		&i.OsFamily,
		&i.ConfidenceScore,
		&i.ClassificationEvidence,
		&i.ClassificationLocked,
		&i.Subtype,
		&i.Notes,
		&i.Criticality,
		&i.MonitoringEnabled,
		&i.ManualClassificationReason,
		&i.IsVirtual,
	)
	return i, err
}

const updateDeviceClassification = `-- name: UpdateDeviceClassification :one
UPDATE devices SET
    category = $2,
    os_family = $3,
    device_class = $4,
    confidence_score = $5,
    classification_evidence = $6,
    updated_at = now()
WHERE id = $1 AND deleted_at IS NULL AND classification_locked = false
RETURNING id, location_id, primary_ip, hostname, name, vendor, model, serial, os_version, category, status, driver, credential_id, last_discovery_at, last_monitoring_at, metadata, created_at, updated_at, deleted_at, vlan, device_class, location, os_family, confidence_score, classification_evidence, classification_locked, subtype, notes, criticality, monitoring_enabled, manual_classification_reason, is_virtual
`

type UpdateDeviceClassificationParams struct {
	ID                     uuid.UUID `json:"id"`
	Category               string    `json:"category"`
	OsFamily               string    `json:"os_family"`
	DeviceClass            *string   `json:"device_class"`
	ConfidenceScore        *int16    `json:"confidence_score"`
	ClassificationEvidence []byte    `json:"classification_evidence"`
}

// Auto-classification write: set category + OS family + subtype + confidence +
// evidence trail in one shot. The `classification_locked = false` guard makes
// this an atomic no-op on operator-overridden devices (0 rows affected →
// pgx.ErrNoRows), so a manual classification is never silently overwritten.
func (q *Queries) UpdateDeviceClassification(ctx context.Context, arg UpdateDeviceClassificationParams) (Device, error) {
	row := q.db.QueryRow(ctx, updateDeviceClassification,
		arg.ID,
		arg.Category,
		arg.OsFamily,
		arg.DeviceClass,
		arg.ConfidenceScore,
		arg.ClassificationEvidence,
	)
	var i Device
	err := row.Scan(
		&i.ID,
		&i.LocationID,
		&i.PrimaryIp,
		&i.Hostname,
		&i.Name,
		&i.Vendor,
		&i.Model,
		&i.Serial,
		&i.OsVersion,
		&i.Category,
		&i.Status,
		&i.Driver,
		&i.CredentialID,
		&i.LastDiscoveryAt,
		&i.LastMonitoringAt,
		&i.Metadata,
		&i.CreatedAt,
		&i.UpdatedAt,
		&i.DeletedAt,
		&i.Vlan,
		&i.DeviceClass,
		&i.Location,
		&i.OsFamily,
		&i.ConfidenceScore,
		&i.ClassificationEvidence,
		&i.ClassificationLocked,
		&i.Subtype,
		&i.Notes,
		&i.Criticality,
		&i.MonitoringEnabled,
		&i.ManualClassificationReason,
		&i.IsVirtual,
	)
	return i, err
}

const updateDeviceHardwareInfo = `-- name: UpdateDeviceHardwareInfo :exec
UPDATE devices SET
    vendor = COALESCE(NULLIF($1::text, ''), vendor),
    model = COALESCE(NULLIF($2::text, ''), model),
    serial = COALESCE(NULLIF($3::text, ''), serial),
    os_version = COALESCE(NULLIF($4::text, ''), os_version),
    hostname = COALESCE(NULLIF($5::text, ''), hostname),
    updated_at = now()
WHERE id = $6 AND deleted_at IS NULL
`

type UpdateDeviceHardwareInfoParams struct {
	Vendor    string    `json:"vendor"`
	Model     string    `json:"model"`
	Serial    string    `json:"serial"`
	OsVersion string    `json:"os_version"`
	Hostname  string    `json:"hostname"`
	ID        uuid.UUID `json:"id"`
}

// Fill the device's identity/hardware fields from an authenticated deep-OS
// collection (manufacturer/model/serial/OS caption/hostname). COALESCE(NULLIF…)
// means a blank incoming value never wipes an existing one — collection only
// ENRICHES the row, so the Inventory list columns (Vendor/Model/OS) populate
// without clobbering anything a prior SNMP probe or operator edit set.
func (q *Queries) UpdateDeviceHardwareInfo(ctx context.Context, arg UpdateDeviceHardwareInfoParams) error {
	_, err := q.db.Exec(ctx, updateDeviceHardwareInfo,
		arg.Vendor,
		arg.Model,
		arg.Serial,
		arg.OsVersion,
		arg.Hostname,
		arg.ID,
	)
	return err
}

